// ===================================================
// WF-06 Step 1: POST 본문 파싱 + 입력값 검증
// 필수 필드: member_id, class_id, status
// status 유효값: active, paused, closed
// ===================================================

const input = $input.first().json;
const body = input.body || input;

// === 텍스트 정제 (제어 문자 제거 + 길이 제한) ===
function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .trim()
    .substring(0, maxLen);
}

// === 필수 필드 추출 ===
const memberId = sanitizeText(body.member_id, 100);
const classId = sanitizeText(body.class_id, 100);
const newStatus = sanitizeText(body.status, 20).toLowerCase();

// === 필수 필드 검증 ===
const missingFields = [];
if (!memberId) missingFields.push('member_id');
if (!classId) missingFields.push('class_id');
if (!newStatus) missingFields.push('status');

if (missingFields.length > 0) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'MISSING_PARAMS',
          message: missingFields.join(', ') + ' 파라미터가 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === status 유효값 검증 ===
const validStatuses = ['active', 'paused', 'closed'];
if (!validStatuses.includes(newStatus)) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_PARAMS',
          message: 'status는 active, paused, closed 중 하나여야 합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _valid: true,
    memberId,
    classId,
    newStatus
  }
}];

// ===================================================
// WF-06 Step 2: 파트너 인증 확인
// member_id로 조회한 파트너가 존재하고 active 상태인지 검증
// ===================================================

const response = $input.first().json;
const partnerList = response.list || [];
const validData = $('Validate Input').first().json;

if (partnerList.length === 0) {
  return [{
    json: {
      _partnerFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'NOT_PARTNER',
          message: '파트너로 등록되지 않은 회원입니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const partner = partnerList[0];

// 파트너 상태 확인
if (partner.status !== 'active') {
  return [{
    json: {
      _partnerFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'PARTNER_INACTIVE',
          message: '비활성 상태의 파트너 계정입니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _partnerFound: true,
    _partner: {
      partner_code: partner.partner_code || '',
      partner_name: partner.partner_name || '',
      member_id: partner.member_id || '',
      grade: partner.grade || 'SILVER'
    },
    _input: validData
  }
}];

// ===================================================
// WF-06 Step 3: 클래스 존재 여부 + 소유권 확인
// partner_code가 일치하는지 검증하여 타 파트너 클래스 변경 차단
// ===================================================

const response = $input.first().json;
const classList = response.list || [];
const prevData = $('Check Partner Auth').first().json;
const partner = prevData._partner;
const inputData = prevData._input;

// 클래스 존재 확인
if (classList.length === 0) {
  return [{
    json: {
      _classOwned: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'CLASS_NOT_FOUND',
          message: '해당 클래스를 찾을 수 없습니다.'
        },
        timestamp: new Date().toISOString()
      },
      _errorCode: 404
    }
  }];
}

const classRecord = classList[0];

// partner_code 추출 (Links 필드 또는 문자열 대응)
let classPartnerCode = '';
if (Array.isArray(classRecord.partner_code) && classRecord.partner_code.length > 0) {
  classPartnerCode = classRecord.partner_code[0].partner_code || classRecord.partner_code[0].Title || '';
} else if (typeof classRecord.partner_code === 'string') {
  classPartnerCode = classRecord.partner_code;
}

// 소유권 확인: 요청 파트너의 partner_code와 클래스의 partner_code 비교
if (classPartnerCode !== partner.partner_code) {
  return [{
    json: {
      _classOwned: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'CLASS_NOT_FOUND',
          message: '본인 소유의 클래스만 수정할 수 있습니다.'
        },
        timestamp: new Date().toISOString()
      },
      _errorCode: 403
    }
  }];
}

return [{
  json: {
    _classOwned: true,
    _classRecord: {
      Id: classRecord.Id || classRecord.id,
      class_id: classRecord.class_id || '',
      class_name: classRecord.class_name || '',
      old_status: classRecord.status || '',
      partner_code: classPartnerCode
    },
    _partner: partner,
    _newStatus: inputData.newStatus
  }
}];

// ===================================================
// WF-06 Step 4: 텔레그램 알림 메시지 구성 + 성공 응답 준비
// ===================================================

const updateResult = $input.first().json;
const classData = $('Check Class Ownership').first().json._classRecord;
const partner = $('Check Class Ownership').first().json._partner;
const newStatus = $('Check Class Ownership').first().json._newStatus;

// 상태 한국어 매핑
const statusLabels = {
  active: '활성',
  paused: '일시정지',
  closed: '마감'
};

const oldLabel = statusLabels[classData.old_status] || classData.old_status;
const newLabel = statusLabels[newStatus] || newStatus;

// 텔레그램 메시지
const telegramMessage = '[클래스 상태 변경]\n\n'
  + '클래스: ' + classData.class_name + '\n'
  + '파트너: ' + partner.partner_name + ' (' + partner.partner_code + ')\n'
  + '변경: ' + oldLabel + ' -> ' + newLabel + '\n'
  + '시각: ' + new Date().toISOString();

// 성공 응답
const successResponse = {
  success: true,
  data: {
    class_id: classData.class_id,
    class_name: classData.class_name,
    old_status: classData.old_status,
    new_status: newStatus,
    message: '클래스 상태가 변경되었습니다.'
  },
  timestamp: new Date().toISOString()
};

return [{
  json: {
    _telegramMessage: telegramMessage,
    _successResponse: successResponse
  }
}];
